#include <stdio.h>
#include <stdlib.h>
#define MOD 108
long long comb[100001][100001];
void precalc() {
    for (int i = 0; i <= 100000; i++) {
        comb[i][0] = 1;
        comb[i][i] = 1;
    }
    for (int i = 1; i <= 100000; i++) {
        for (int j = 1; j < i; j++) {
            comb[i][j] = (comb[i-1][j-1] + comb[i-1][j]) % MOD;
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    precalc();
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        printf("%lld\n", comb[N][K]);
    }
    return 0;
}

